VALUES
  ('immigration-1aab856d-moex-00290', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依公務人員考績法規定，關於公務人員考績之敘述，下列何者正確？', '["專案考績獎懲不得與平時考核功過抵銷，但年終考績連續3年甲等者得例外抵銷之", "平時考核無獎懲抵銷而累積達二大過者，年終考績應列丁等，停止職務3年", "平時考核之獎勵僅得為嘉獎、記功；懲處僅得為申誡、記過", "年終考績乙等，應晉本俸一級，並給與半個月俸給總額之一次獎金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00291', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於公務人員提起申訴、再申訴，下列敘述何者正確？', '["公務人員對於服務機關所為之管理措施或有關工作條件之處置認為不當，致影響其權益 者，得依法提起申訴、再申訴", "公務人員離職後，始接獲原服務機關之管理措施或處置者，不得提起申訴、再申訴", "申訴之提起，應於管理措施或有關工作條件之處置達到之次日起至遲於 10 日內，向公務 人員保障暨培訓委員會為之", "公務人員不服服務機關函復者，得於復函送達之次日起30日內，向服務機關提起再申訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00292', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於法規命令之敘述，下列何者正確？', '["法律授權主管機關依一定程序訂定命令以補充法律規定不足時，該機關亦可發布規範行政 體系內部事項之行政規則以為替代", "若僅屬執行法律之細節性、技術性事項，縱僅對人民產生不便或輕微影響，亦應以制定法 律或以法律明確授權訂定命令之方式為之", "關於給付行政措施，倘涉及公共利益之重大事項，應有法律或法律明確授權之命令為依據", "全民健康保險法規定：「本法施行細則，由主管機關定之。」雖屬概括性授權規定，仍可 從寬認定該條就全民健保是否得停保及復保等事項已有默示之授權，尚屬明確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00293', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依司法實務見解，法規命令僅於機關網站上公告，而未刊登政府公報或新聞紙時，其效力 如何？', '["不生效力", "仍生效力，但應補正", "仍生效力，不必補正", "效力未定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00294', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者為行政處分？', '["公平交易委員會就消費者檢舉不實廣告，作成不成立之決定", "行政機關代表國庫出租公有財產", "行政機關答覆人民對於法規適用之詢問", "會計師懲戒處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00295', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者屬於一般處分？', '["警察機關對違法集會作成解散處分", "警察機關攔停疑似酒駕之駕駛人", "環境部發布空氣品質惡化之警告", "公物特別利用之許可"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00296', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於行政處分廢止之敘述，下列何者錯誤？', '["附負擔之授益行政處分，受益人未履行該負擔，處分機關得廢止該行政處分", "行政機關依行政程序法規定廢止授益行政處分，得依職權為全部或一部之廢止", "行政機關依行政程序法規定，廢止授益處分，應於知悉廢止原因時起2年內為之", "行政機關作成授益處分，其內容係提供金錢給付，該處分經行政機關為溯及既往失效之廢 止，行政機關得作成行政處分命受益人返還其因該處分所受領之金錢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00297', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於行政契約之敘述，下列何者正確？', '["契約當事人之一方為人民，行政機關依法應以甄選方式決定時，如未事先公告應具資格及 決定之程序，該瑕疵得事後補正", "行政契約，行政程序法未規定者，準用政府採購法相關之規定", "行政契約約定自願接受執行時，締約之一方為地方自治團體之行政機關時，應向該地方自 治團體行政首長報備", "替代行政處分之行政契約，如與其內容相同之行政處分有得撤銷之違法原因，並為締約雙 方所明知者，為無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00298', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者非屬行政法上之事實行為？', '["依文化資產保存法規定，對古物進行修復", "依精神衛生法規定，強制病人住院治療", "國家公園管制站以天候因素，建議民眾不宜前往登山", "教育部通報各學校不適任教師之名單"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00299', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依行政罰法規定，下列何者得為沒入之標的？', '["不屬於受處罰者所有之物，因所有人之抽象輕過失，致使該物成為違反行政法上義務行為 之工具者", "應受處罰者為規避其所有物遭沒入而移轉時，第三人因重大過失不知而取得該物所有權", "受處罰者所有之物，受處罰者於受裁處沒入前，予以處分或使用致不能裁處沒入時，該物 之價額", "受處罰者所有之物，受處罰者於受裁處沒入後，予以處分或使用致不能執行沒入者，該物 之價額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
